'use client';

import { useState, useEffect, createContext, useContext, createElement } from 'react';
import type { ReactNode } from 'react';

interface SiteSettings {
  logo: {
    lightUrl: string;
    darkUrl: string;
    alt: string;
    width: number;
    height: number;
  };
  languages: {
    showInHeader: boolean;
    defaultLanguage: string;
    enabledLanguages: string[];
  };
  contactSales: {
    show: boolean;
    text: string;
    url: string;
  };
  theme: {
    defaultTheme: 'light' | 'dark' | 'system';
    autoSwitchByTime: boolean;
    darkModeStart: string;
    darkModeEnd: string;
  };
  favicon: {
    url: string;
    appleTouchIcon: string;
    manifest: string;
  };
}

const defaultSettings: SiteSettings = {
  logo: {
    lightUrl: '',
    darkUrl: '',
    alt: 'English Website',
    width: 120,
    height: 40
  },
  languages: {
    showInHeader: true,
    defaultLanguage: 'en',
    enabledLanguages: ['en', 'ar']
  },
  contactSales: {
    show: true,
    text: 'Contact Sales',
    url: '/contact-sales'
  },
  theme: {
    defaultTheme: 'light',
    autoSwitchByTime: false,
    darkModeStart: '18:00',
    darkModeEnd: '06:00'
  },
  favicon: {
    url: '/favicon.ico',
    appleTouchIcon: '/apple-touch-icon.png',
    manifest: '/site.webmanifest'
  }
};

interface SiteSettingsContextType {
  settings: SiteSettings;
  isLoading: boolean;
  error: string | null;
  refetch: () => void;
}

const SiteSettingsContext = createContext<SiteSettingsContextType | undefined>(undefined);

interface SiteSettingsProviderProps {
  children: ReactNode;
}

export function SiteSettingsProvider(props: SiteSettingsProviderProps) {
  const [settings, setSettings] = useState<SiteSettings>(defaultSettings);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchSettings = async () => {
    try {
      setIsLoading(true);
      setError(null);
      const response = await fetch('/api/admin/settings');
      if (response.ok) {
        const data = await response.json();
        setSettings({ ...defaultSettings, ...data });
      } else {
        console.warn('Failed to load settings, using defaults');
      }
    } catch (err) {
      console.warn('Failed to load settings, using defaults:', err);
      setError(err instanceof Error ? err.message : 'Failed to load settings');
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchSettings();
  }, []);

  const value = {
    settings,
    isLoading,
    error,
    refetch: fetchSettings
  };

  return createElement(SiteSettingsContext.Provider, { value }, props.children);
}

export function useSiteSettings() {
  const context = useContext(SiteSettingsContext);
  if (context === undefined) {
    throw new Error('useSiteSettings must be used within a SiteSettingsProvider');
  }
  return context;
}